from collections import Counter

def rouge_scores(hypothesis: list[str], reference: list[str]) -> dict:
    def ngram_f1(hyp, ref, n):
        def ngrams(tokens, n):
            return Counter(tuple(tokens[i:i+n]) for i in range(len(tokens)-n+1))
        h = ngrams(hyp, n)
        r = ngrams(ref, n)
        overlap = sum(min(h[k], r[k]) for k in h)
        p = overlap / max(1, sum(h.values()))
        rc = overlap / max(1, sum(r.values()))
        return 2*p*rc/(p+rc) if (p+rc) > 0 else 0.0

    def lcs_length(a, b):
        m, n = len(a), len(b)
        dp = [[0]*(n+1) for _ in range(m+1)]
        for i in range(1, m+1):
            for j in range(1, n+1):
                if a[i-1] == b[j-1]:
                    dp[i][j] = dp[i-1][j-1] + 1
                else:
                    dp[i][j] = max(dp[i-1][j], dp[i][j-1])
        return dp[m][n]

    lcs = lcs_length(hypothesis, reference)
    p_l = lcs / len(hypothesis) if hypothesis else 0.0
    r_l = lcs / len(reference) if reference else 0.0
    f_l = 2*p_l*r_l/(p_l+r_l) if (p_l+r_l) > 0 else 0.0

    return {
        'rouge1': ngram_f1(hypothesis, reference, 1),
        'rouge2': ngram_f1(hypothesis, reference, 2),
        'rougeL': f_l
    }
